+
+    /* First abort: valid */
+    ASSERT_EQ(asx_obligation_abort(oid), ASX_OK);
+
+    /* Second abort: blocked, ghost records violation */
+    ASSERT_NE(asx_obligation_abort(oid), ASX_OK);
+
+    ASSERT_TRUE(asx_ghost_violation_count() >= (uint32_t)1);
