+
+/* ---- Capture arena exhaustion ---- */
+
+TEST(resource_capture_arena_exhaustion) {
+    asx_region_id rid;
+    asx_task_id tid;
+    void *state;
+    uint32_t capture_remaining;
+    asx_runtime_reset();
+
+    ASSERT_EQ(asx_region_open(&rid), ASX_OK);
