+    ASSERT_EQ(capture_remaining, (uint32_t)ASX_REGION_CAPTURE_ARENA_BYTES);
+
+    /* Allocate a large chunk from the capture arena */
+    ASSERT_EQ(asx_task_spawn_captured(rid, noop_poll,
