+/* ================================================================== */
+/* Violation Ring Buffer Tests                                         */
+/* ================================================================== */
+
+TEST(ghost_violation_get_empty) {
+    asx_ghost_violation v;
+
+    asx_ghost_reset();
+
+    /* No violations recorded */
+    ASSERT_FALSE(asx_ghost_violation_get(0, &v));
